```typescript
// 1. 在 auto-iteration.ts 中添加 Dashboard 通知功能
import { getServices } from './dashboard/server';

export class AutoIterationEngine {
  private notifyDashboard(event: string, data: any) {
    try {
      const { realtimeService } = getServices();
      realtimeService.broadcastEvent(event, data);
    } catch (error) {
      console.error('Failed to notify Dashboard:', error);
    }
  }

  async runIteration() {
    // 迭代开始
    this.notifyDashboard('iteration.started', {
      iteration: this.iterationCount,
      timestamp: new Date()
    });

    // Agent 执行时更新状态
    for (const [name, agent] of Object.entries(this.agents)) {
      this.notifyDashboard('agent.started', {
        agentName: name,
        iteration: this.iterationCount
      });

      const result = await agent.execute(task);

      this.notifyDashboard('agent.completed', {
        agentName: name,
        result: result.substring(0, 1000),
        timestamp: new Date()
      });
    }

    // 迭代完成
    this.notifyDashboard('iteration.completed', {
      iteration: this.iterationCount,
      status: 'success',
      timestamp: new Date()
    });
  }
}
```

**验收标准：**
- ✅ AutoIterationEngine 执行时，前端实时显示进度
- ✅ Agent 状态变化实时更新
- ✅ WebSocket 连接正常，延迟 < 500ms

