#### 任务 4：前端 WebSocket 实时数据处理

**目标：** 确保前端能正确接收并处理实时数据

**实现：**

```typescript
// stores/websocket.ts
export const useWebSocketStore = defineStore('websocket', {
  state: () => ({
    connected: false,
    reconnectAttempts: 0,
    maxReconnectAttempts: 5
  }),

  actions: {
    connect() {
      this.ws = new WebSocket('ws://localhost:3000/api/ws');

      this.ws.onopen = () => {
        this.connected = true;
        this.reconnectAttempts = 0;
        console.log('WebSocket connected');
      };

      this.ws.onmessage = (event) => {
        const { event: eventType, data } = JSON.parse(event.data);

        switch(eventType) {
          case 'iteration.started':
            this.handleIterationStarted(data);
            break;
          case 'agent.started':
            this.handleAgentStarted(data);
            break;
          case 'agent.completed':
            this.handleAgentCompleted(data);
            break;
          case 'iteration.completed':
            this.handleIterationCompleted(data);
            break;
          case 'system.metrics':
            this.handleMetrics(data);
            break;
        }
      };

      this.ws.onclose = () => {
        this.connected = false;
        if (this.reconnectAttempts < this.maxReconnectAttempts) {
          setTimeout(() => {
            this.reconnectAttempts++;
            this.connect();
          }, 3000);
        }
      };
    },

    handleIterationStarted(data) {
      const iterationStore = useIterationStore();
      iterationStore.setCurrentIteration(data);
    },

    handleAgentStarted(data) {
      const agentStore = useAgentStore();
      agentStore.updateAgentStatus(data.agentName, 'running');
    },

    handleAgentCompleted(data) {
      const agentStore = useAgentStore();
      agentStore.updateAgentStatus(data.agentName, 'completed');
      agentStore.addAgentResult(data);
    }
  }
});
```

