   // src/dashboard/services/log.service.ts
   export class LogService {
     async add(entry: {
       level: string
       message: string
       source?: string
       metadata?: any
     }) {
       await this.db.run(
         'INSERT INTO logs (level, message, source, metadata, timestamp) VALUES (?, ?, ?, ?, ?)',
         [entry.level, entry.message, entry.source, JSON.stringify(entry.metadata || {}), new Date()]
       )
     }

     async query(options: {
       level?: string
       source?: string
       startTime?: Date
       endTime?: Date
       limit?: number
     }) {
       let query = 'SELECT * FROM logs WHERE 1=1'
       const params: any[] = []

       if (options.level) {
         query += ' AND level = ?'
         params.push(options.level)
       }

       if (options.source) {
         query += ' AND source = ?'
         params.push(options.source)
       }

       query += ' ORDER BY timestamp DESC LIMIT ?'
       params.push(options.limit || 1000)

       return this.db.all(query, params)
     }
   }
   ```

2. **前端日志导出功能**
   ```typescript
   // dashboard/src/utils/log-export.ts
   export function exportLogs(logs: any[], format: 'json' | 'txt' | 'csv') {
     switch (format) {
       case 'json':
         return JSON.stringify(logs, null, 2)

       case 'csv':
         const headers = ['timestamp', 'level', 'source', 'message']
         const rows = logs.map(log => [
           log.timestamp,
           log.level,
           log.source || '',
           `"${log.message.replace(/"/g, '""')}"`
         ])
         return [headers.join(','), ...rows.map(r => r.join(','))].join('\n')

       case 'txt':
         return logs.map(log =>
           `[${log.timestamp}] [${log.level}] ${log.source || ''}: ${log.message}`
         ).join('\n')
     }
   }
   ```

